1	import type { QueryClient } from "@tanstack/react-query";
2	import { apiClient, isOfflineApiError } from "@/lib/api-client";
3	import {
4	  loadPendingOfflineMutations,
5	  removeOfflineMutation,
6	  type OfflineMutationEntry,
7	} from "@/lib/offline-cache";
8	
9	function isBrowserOffline(): boolean {
10	  return typeof navigator !== "undefined" && !navigator.onLine;
11	}
12	
13	async function executeMutation(entry: OfflineMutationEntry): Promise<void> {
14	  switch (entry.type) {
15	    case "create-item":
16	      await apiClient.post("/items", entry.payload);
17	      return;
18	    case "update-item": {
19	      const id = entry.payload.id;
20	      const body = entry.payload.body;
21	      if (typeof id !== "string" || !body || typeof body !== "object") {
22	        return;
23	      }
24	      await apiClient.put(`/items/${id}`, body);
25	      return;
26	    }
27	    case "run-export":
28	      await apiClient.post("/exports", entry.payload);
29	      return;
30	    default:
31	      return;
32	  }
33	}
34	
35	export async function replayOfflineMutations(
36	  queryClient: QueryClient,
37	): Promise<number> {
38	  if (isBrowserOffline()) {
39	    return 0;
40	  }
41	
42	  const queue = await loadPendingOfflineMutations();
43	  let processed = 0;
44	
45	  for (const entry of queue) {
46	    try {
47	      await executeMutation(entry);
48	      await removeOfflineMutation(entry.id);
49	      processed += 1;
50	    } catch (error) {
51	      if (isOfflineApiError(error)) {
52	        break;
53	      }
54	      await removeOfflineMutation(entry.id);
55	    }
56	  }
57	
58	  if (processed > 0) {
59	    queryClient.invalidateQueries({ queryKey: ["items"] });
60	    queryClient.invalidateQueries({ queryKey: ["reports"] });
61	    queryClient.invalidateQueries({ queryKey: ["exports"] });
62	  }
63	
64	  return processed;
65	}
