1	import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
2	import { apiClient, type ApiEnvelope, type ApiMessage, type PaginatedResponse } from '@/lib/api-client';
3	import { enqueueOfflineMutation } from '@/lib/offline-cache';
4	import type { BatchEditResponse, Item } from '@/lib/types';
5	
6	interface ItemFilters {
7	  category?: string;
8	  brand?: string;
9	  condition?: string;
10	  status?: string;
11	}
12	
13	interface ItemListParams extends ItemFilters {
14	  page?: number;
15	  page_size?: number;
16	}
17	
18	export function useItemList(params: ItemListParams = {}) {
19	  return useQuery({
20	    queryKey: ['items', params],
21	    queryFn: () =>
22	      apiClient.get<PaginatedResponse<Item>>('/items', {
23	        page: params.page ?? 1,
24	        page_size: params.page_size ?? 20,
25	        category: params.category,
26	        brand: params.brand,
27	        condition: params.condition,
28	        status: params.status,
29	      }),
30	  });
31	}
32	
33	export function useItem(id: string | undefined) {
34	  return useQuery({
35	    queryKey: ['items', id],
36	    queryFn: async () => {
37	      const response = await apiClient.get<ApiEnvelope<Item>>(`/items/${id}`);
38	      return response.data;
39	    },
40	    enabled: Boolean(id),
41	  });
42	}
43	
44	export function usePublishItem() {
45	  const qc = useQueryClient();
46	  return useMutation({
47	    mutationFn: (id: string) => apiClient.post<ApiEnvelope<ApiMessage>>(`/items/${id}/publish`, {}),
48	    onSuccess: (_, id) => {
49	      qc.invalidateQueries({ queryKey: ['items'] });
50	      qc.invalidateQueries({ queryKey: ['items', id] });
51	    },
52	  });
53	}
54	
55	export function useUnpublishItem() {
56	  const qc = useQueryClient();
57	  return useMutation({
58	    mutationFn: (id: string) => apiClient.post<ApiEnvelope<ApiMessage>>(`/items/${id}/unpublish`, {}),
59	    onSuccess: (_, id) => {
60	      qc.invalidateQueries({ queryKey: ['items'] });
61	      qc.invalidateQueries({ queryKey: ['items', id] });
62	    },
63	  });
64	}
65	
66	interface UpdateItemPayload {
67	  id: string;
68	  body: Record<string, unknown>;
69	}
70	
71	export function useUpdateItem() {
72	  const qc = useQueryClient();
73	  return useMutation({
74	    mutationFn: async ({ id, body }: UpdateItemPayload) => {
75	      if (typeof navigator !== 'undefined' && !navigator.onLine) {
76	        await enqueueOfflineMutation({
77	          id: globalThis.crypto?.randomUUID?.() ?? `${Date.now()}-update-item`,
78	          type: 'update-item',
79	          payload: { id, body },
80	          createdAt: Date.now(),
81	        });
82	        return { id, ...(body as Record<string, unknown>) } as Item;
83	      }
84	      const response = await apiClient.put<ApiEnvelope<Item>>(`/items/${id}`, body);
85	      return response.data;
86	    },
87	    onSuccess: (_, { id }) => {
88	      qc.invalidateQueries({ queryKey: ['items'] });
89	      qc.invalidateQueries({ queryKey: ['items', id] });
90	    },
91	  });
92	}
93	
94	export interface BatchEditWindowInput {
95	  start_time: string;
96	  end_time: string;
97	}
98	
99	export interface BatchEditRow {
100	  item_id: string;
101	  field: string;
102	  new_value?: string;
103	  availability_windows?: BatchEditWindowInput[];
104	}
105	
106	export function useBatchEdit() {
107	  const qc = useQueryClient();
108	  return useMutation({
109	    mutationFn: async (edits: BatchEditRow[]) => {
110	      const response = await apiClient.post<ApiEnvelope<BatchEditResponse>>('/items/batch-edit', { edits });
111	      return response.data;
112	    },
113	    onSuccess: () => {
114	      qc.invalidateQueries({ queryKey: ['items'] });
115	    },
116	  });
117	}
118	
119	export function useCreateItem() {
120	  const qc = useQueryClient();
121	  return useMutation({
122	    mutationFn: async (body: Record<string, unknown>) => {
123	      if (typeof navigator !== 'undefined' && !navigator.onLine) {
124	        const queuedID = globalThis.crypto?.randomUUID?.() ?? `${Date.now()}-create-item`;
125	        await enqueueOfflineMutation({
126	          id: queuedID,
127	          type: 'create-item',
128	          payload: body,
129	          createdAt: Date.now(),
130	        });
131	        return { id: queuedID, ...(body as Record<string, unknown>) } as Item;
132	      }
133	      const response = await apiClient.post<ApiEnvelope<Item>>('/items', body);
134	      return response.data;
135	    },
136	    onSuccess: () => {
137	      qc.invalidateQueries({ queryKey: ['items'] });
138	    },
139	  });
140	}
