36	export default function CatalogFormPage() {
37	  const { id } = useParams<{ id: string }>();
38	  const navigate = useNavigate();
39	  const notify = useNotify();
40	  const { isOffline } = useOfflineStatus();
41	  const isEdit = Boolean(id);
42	
43	  const { data: existingItem, isLoading: itemLoading, error, dataUpdatedAt } = useItem(isEdit ? id : undefined);
44	  const createMutation = useCreateItem();
45	  const updateMutation = useUpdateItem();
46	
47	  const {
48	    register,
49	    handleSubmit,
50	    control,
51	    reset,
52	    setError,
53	    formState: { errors, isSubmitting },
54	  } = useForm<CreateItemFormData>({
55	    resolver: zodResolver(createItemSchema),
56	    defaultValues: getDefaultCatalogFormValues(),
57	  });
58	
59	  const availabilityWindows = useFieldArray({
60	    control,
61	    name: 'availability_windows',
62	  });
63	
64	  const blackoutWindows = useFieldArray({
65	    control,
66	    name: 'blackout_windows',
67	  });
68	
69	  useEffect(() => {
70	    if (existingItem) {
71	      reset(mapItemToCatalogFormValues(existingItem));
72	    } else if (!isEdit) {
73	      reset(getDefaultCatalogFormValues());
74	    }
75	  }, [existingItem, isEdit, reset]);
76	
77	  const onSubmit = async (data: CreateItemFormData) => {
78	    try {
79	      const payload = mapCatalogFormToItemPayload(data);
80	
81	      if (isEdit && id) {
82	        if (!existingItem) {
83	          throw new Error('Item data is missing');
84	        }
85	
86	        await updateMutation.mutateAsync({
87	          id,
88	          body: { ...payload, version: existingItem.version },
89	        });
90	        notify.success(isOffline ? 'Item update queued. It will sync when you reconnect.' : 'Item updated successfully.');
91	        navigate(`/catalog/${id}`);
92	      } else {
93	        const createdItem = await createMutation.mutateAsync(payload);
94	        notify.success(isOffline ? 'Item draft queued. It will sync when you reconnect.' : 'Item saved as a draft.');
95	        navigate(createdItem?.id ? `/catalog/${createdItem.id}` : '/catalog');
96	      }
97	    } catch (err: unknown) {
98	      const apiErr = err as { status?: number; message?: string };
99	      if (apiErr.status === 409) {
100	        setError('root', { message: 'Item was modified by another user. Please reload and try again.' });
101	      } else if (apiErr.status === 422) {
102	        setError('root', { message: `Validation error: ${apiErr.message ?? 'Please check your inputs.'}` });
103	      } else {
104	        setError('root', { message: 'Failed to save item. Please try again.' });
105	      }
106	    }
107	  };
108	
109	  if (isEdit && itemLoading) {
110	    return (
111	      <PageContainer title="Edit Item" breadcrumbs={[{ label: 'Catalog', to: '/catalog' }, { label: 'Edit' }]}>
112	        <Skeleton variant="rectangular" height={400} />
113	      </PageContainer>
114	    );
115	  }
116	
117	  const title = isEdit ? `Edit ${existingItem?.name ?? 'Item'}` : 'Create Item';
118	
119	  return (
120	    <PageContainer
121	      title={title}
122	      breadcrumbs={[
123	        { label: 'Catalog', to: '/catalog' },
124	        ...(isEdit && id ? [{ label: existingItem?.name ?? id, to: `/catalog/${id}` }] : []),
125	        { label: isEdit ? 'Edit' : 'Create' },
126	      ]}
127	    >
128	      <Paper variant="outlined" sx={{ p: 3 }}>
129	        <Box component="form" onSubmit={handleSubmit(onSubmit)} noValidate>
130	          <OfflineDataNotice hasData={Boolean(existingItem) || !isEdit} dataUpdatedAt={dataUpdatedAt} />
131	
132	          {isOffline && (
133	            <Alert severity="warning" sx={{ mb: 2 }}>
134	              {OFFLINE_MUTATION_MESSAGE} Catalog edits are queued locally and will sync once connectivity returns.
135	            </Alert>
136	          )}
137	
138	          {error && isEdit && (
139	            <Alert severity="warning" sx={{ mb: 2 }}>
140	              Catalog sync is temporarily unavailable. Showing the latest cached draft details when possible.
141	            </Alert>
142	          )}
143	
144	          {errors.root && (
145	            <Alert severity="error" sx={{ mb: 2 }}>
146	              {errors.root.message}
147	            </Alert>
148	          )}
149	
150	          <Typography variant="subtitle2" fontWeight={600} gutterBottom>
151	            Basic Information
152	          </Typography>
153	          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
154	            New catalog items are saved as drafts until they are explicitly published.
155	          </Typography>
156	          <Grid container spacing={2} sx={{ mb: 3 }}>
157	            <Grid item xs={12} md={6}>
158	              <TextField
159	                {...register('name')}
160	                label="Name"
161	                fullWidth
162	                size="small"
163	                required
164	                error={Boolean(errors.name)}
165	                helperText={errors.name?.message}
166	              />
167	            </Grid>
168	            <Grid item xs={12} md={6}>
169	              <TextField
170	                {...register('sku')}
171	                label="SKU"
172	                fullWidth
173	                size="small"
174	                error={Boolean(errors.sku)}
175	                helperText={errors.sku?.message}
176	              />
177	            </Grid>
178	            <Grid item xs={12}>
179	              <TextField
180	                {...register('description')}
181	                label="Description"
182	                fullWidth
183	                size="small"
184	                multiline
185	                rows={3}
186	                error={Boolean(errors.description)}
187	                helperText={errors.description?.message}
188	              />
189	            </Grid>
190	            <Grid item xs={12} md={4}>
191	              <TextField
192	                {...register('category')}
193	                label="Category"
194	                fullWidth
195	                size="small"
196	                required
197	                error={Boolean(errors.category)}
198	                helperText={errors.category?.message}
