20	    "members",
21	    "coaches",
22	    "landed-costs",
23	  ] as const;
24	
25	  for (const root of operationalRoots) {
26	    it(`caches queries with root "${root}"`, () => {
27	      expect(isOfflineCacheableQueryKey([root])).toBe(true);
28	      expect(isOfflineCacheableQueryKey([root, { page: 1 }])).toBe(true);
29	    });
30	  }
31	});
32	
33	// ─── Admin read domains (offline coverage fix) ────────────────────────────────
34	
35	describe("isOfflineCacheableQueryKey — admin read domains", () => {
36	  it('caches "users" queries (useUserList, useUser)', () => {
37	    expect(isOfflineCacheableQueryKey(["users"])).toBe(true);
38	    expect(
39	      isOfflineCacheableQueryKey(["users", { page: 1, role: "coach" }]),
40	    ).toBe(true);
41	    expect(isOfflineCacheableQueryKey(["users", "user-uuid-123"])).toBe(true);
42	  });
43	
44	  it('caches "audit" queries (useAuditLog, useSecurityEvents)', () => {
45	    expect(isOfflineCacheableQueryKey(["audit"])).toBe(true);
46	    expect(isOfflineCacheableQueryKey(["audit", { page: 1 }])).toBe(true);
47	    expect(isOfflineCacheableQueryKey(["audit", "security", { page: 1 }])).toBe(
48	      true,
49	    );
50	  });
51	
52	  it('caches "backups" queries (useBackupList)', () => {
53	    expect(isOfflineCacheableQueryKey(["backups"])).toBe(true);
54	    expect(isOfflineCacheableQueryKey(["backups", { page: 1 }])).toBe(true);
55	  });
56	
57	  it('caches "biometrics" queries (useBiometric)', () => {
58	    expect(isOfflineCacheableQueryKey(["biometrics"])).toBe(true);
59	    expect(isOfflineCacheableQueryKey(["biometrics", "user-uuid-456"])).toBe(
60	      true,
61	    );
62	  });
63	
64	  it('caches "encryption-keys" queries (useEncryptionKeys)', () => {
65	    expect(isOfflineCacheableQueryKey(["encryption-keys"])).toBe(true);
66	  });
67	
68	  it('caches "retention-policies" queries (useRetentionPolicies)', () => {
69	    expect(isOfflineCacheableQueryKey(["retention-policies"])).toBe(true);
70	  });
71	});
72	
73	// ─── Non-cacheable roots ──────────────────────────────────────────────────────
74	
75	describe("isOfflineCacheableQueryKey — non-cacheable roots", () => {
76	  it("rejects unknown roots", () => {
77	    expect(isOfflineCacheableQueryKey(["unknown-root"])).toBe(false);
78	    expect(isOfflineCacheableQueryKey(["admin"])).toBe(false);
79	    expect(isOfflineCacheableQueryKey(["auth"])).toBe(false);
80	    expect(isOfflineCacheableQueryKey(["session"])).toBe(false);
81	  });
82	});
83	
84	// ─── Edge cases ───────────────────────────────────────────────────────────────
85	
86	describe("isOfflineCacheableQueryKey — edge cases", () => {
87	  it("rejects an empty array key", () => {
88	    expect(isOfflineCacheableQueryKey([])).toBe(false);
89	  });
90	
91	  it("rejects a non-array scalar key", () => {
92	    const scalarKey = "orders" as unknown as readonly unknown[];
93	    expect(isOfflineCacheableQueryKey(scalarKey)).toBe(false);
94	  });
95	
96	  it("rejects an array whose first element is not a string", () => {
97	    expect(isOfflineCacheableQueryKey([42])).toBe(false);
