385	// DownloadExport returns the file path for a completed export job. Access is
386	// granted to the creator or to roles with administrative report access.
387	func (s *ReportServiceImpl) DownloadExport(ctx context.Context, id uuid.UUID, callerID uuid.UUID, callerRole domain.UserRole) (*domain.ExportJob, error) {
388		job, err := s.exportRepo.GetByID(ctx, id)
389		if err != nil {
390			return nil, err
391		}
392		isOwner := job.CreatedBy == callerID
393		isAdmin := callerRole == domain.UserRoleAdministrator || callerRole == domain.UserRoleOperationsManager
394		if !isOwner && !isAdmin {
395			return nil, domain.ErrForbidden
396		}
397		if job.Status != domain.ExportStatusCompleted {
398			return nil, &domain.ErrConflict{Entity: "export", Message: "export is not ready for download"}
399		}
400		if job.FilePath == "" {
401			return nil, domain.ErrNotFound
402		}
403		if _, err := os.Stat(job.FilePath); err != nil {
404			if os.IsNotExist(err) {
405				return nil, domain.ErrNotFound
406			}
407			return nil, fmt.Errorf("report.DownloadExport stat: %w", err)
408		}
409		return job, nil
410	}
