442	// maskExportRecords applies role-based field masking to export records.
443	// Administrators and OperationsManagers see all data unmasked.
444	// All other roles have email addresses masked and phone/contact fields redacted.
445	func maskExportRecords(records []map[string]interface{}, role domain.UserRole) []map[string]interface{} {
446		if role == domain.UserRoleAdministrator || role == domain.UserRoleOperationsManager {
447			return records
448		}
449		masked := make([]map[string]interface{}, len(records))
450		for i, rec := range records {
451			m := make(map[string]interface{}, len(rec))
452			for k, v := range rec {
453				switch k {
454				case "email", "contact_email", "user_email":
455					if s, ok := v.(string); ok {
456						m[k] = maskExportEmail(s)
457					} else {
458						m[k] = v
459					}
460				case "phone", "contact_phone":
461					m[k] = "[REDACTED]"
462				default:
463					m[k] = v
464				}
465			}
466			masked[i] = m
467		}
468		return masked
469	}
