174	// buildFilteredQuery appends parameterized WHERE clauses to a base query using
175	// the provided filter map and column mapping. The "_date" key in colMap defines
176	// which column is used for "from" and "to" range filters. Returns the final
177	// query string and the argument slice.
178	func buildFilteredQuery(baseQuery string, filters map[string]string, colMap map[string]string, suffix string) (string, []interface{}) {
179		q := baseQuery
180		args := []interface{}{}
181		n := 1
182		hasWhere := strings.Contains(strings.ToUpper(baseQuery), "WHERE")
183		conj := func() string {
184			if hasWhere {
185				return " AND "
186			}
187			hasWhere = true
188			return " WHERE "
189		}
190	
191		for filterKey, colName := range colMap {
192			if filterKey == "_date" {
193				continue
194			}
195			if v, ok := filters[filterKey]; ok && v != "" {
196				q += conj() + fmt.Sprintf("%s = $%d", colName, n)
197				args = append(args, v)
198				n++
199			}
200		}
201	
202		dateCol := colMap["_date"]
203		if dateCol != "" {
204			if v, ok := filters["from"]; ok && v != "" {
205				q += conj() + fmt.Sprintf("%s >= $%d", dateCol, n)
206				args = append(args, v)
207				n++
208			}
209			if v, ok := filters["to"]; ok && v != "" {
210				q += conj() + fmt.Sprintf("%s <= $%d", dateCol, n)
211				args = append(args, v)
212				n++
213			}
214		}
215	
216		q += suffix
217		return q, args
218	}
