252	// callerRole is checked against the report's AllowedRoles as a second authorization layer.
253	func (s *ReportServiceImpl) GenerateExport(ctx context.Context, reportID uuid.UUID, format domain.ExportFormat, parameters map[string]string, createdBy uuid.UUID, callerRole domain.UserRole) (*domain.ExportJob, error) {
254		if !format.IsValid() {
255			return nil, &domain.ErrValidation{Field: "format", Message: "unsupported export format"}
256		}
257	
258		report, err := s.reportRepo.GetByID(ctx, reportID)
259		if err != nil {
260			return nil, err
261		}
262	
263		allowed := false
264		for _, r := range report.AllowedRoles {
265			if r == callerRole {
266				allowed = true
267				break
268			}
269		}
270		if !allowed {
271			return nil, domain.ErrForbidden
272		}
273	
274		filename := domain.GenerateExportFilename(report.ReportType, format, time.Now().UTC())
275	
276		job := &domain.ExportJob{
277			ID:        uuid.New(),
278			ReportID:  reportID,
279			Format:    format,
280			Filename:  filename,
281			Status:    domain.ExportStatusPending,
282			CreatedBy: createdBy,
283			CreatedAt: time.Now().UTC(),
284		}
285	
286		if err := s.exportRepo.Create(ctx, job); err != nil {
287			return nil, err
288		}
289	
290		filePath := filepath.Join(s.cfg.ExportPath, filename)
291	
292		if err := os.MkdirAll(s.cfg.ExportPath, 0755); err != nil {
293			job.Status = domain.ExportStatusFailed
294			_ = s.exportRepo.Update(ctx, job)
295			return job, err
296		}
297	
298		records, dataErr := s.queryReportData(ctx, report.ReportType, sanitizeReportFilters(report.ReportType, parameters))
299		if dataErr != nil {
300			job.Status = domain.ExportStatusFailed
301			_ = s.exportRepo.Update(ctx, job)
302			return job, dataErr
303		}
